<template>
  <div class="box">
    <div class="msg_box">
      <!-- <div class="olnum">{{ system_info }}在线人数{{ olnum }}</div> -->
      <div class="olnum">在线人数{{ olnum }}</div>
      <ul id="sort_ul">
        <li
          v-for="(item, index) in msg_list"
          :key="index"
          :class="item.source == 'A' ? 'A' : 'B'"
        >
          <span>
            {{
              item.source == "A"
                ? item.msg + " " + item.nickname
                : item.nickname + " " + item.msg
            }}
          </span>
        </li>
      </ul>
    </div>
    <div class="msg_send_box">
      <div class="text">
        <textarea
          cols="30"
          rows="10"
          @keydown.enter.exact="enter"
          @keydown.shift.enter="shift_enter"
          v-model="msg_data"
          :placeholder="input_tps ? '请输入内容' : ''"
        >
        </textarea>
        <div class="tps" @click="tps">Enter发送 Shift+Enter换行</div>
      </div>
    </div>
  </div>
</template>
<script>
import { reactive, toRefs, onMounted, nextTick } from "vue";
import { ElMessage, ElMessageBox } from "element-plus";
export default {
  setup() {
    const data = reactive({
      username: "",
      msg_data: "",
      input_tps: false,
      //******************** */
      olnum: 0,
      msg_list: [],
      system_info: [],
    });
    var ws = new WebSocket("ws://www.xn--lzs769c.cc:3001/");
    const setNmae = () => {
      ElMessageBox.prompt("请输入昵称", "Tip", {
        confirmButtonText: "OK",
        cancelButtonText: "Cancel",
        inputPattern: /^\S{1,5}$/,
        inputErrorMessage: "1~5位任意字符",
      })
        .then(({ value }) => {
          ElMessage({
            type: "success",
            message: `Your email is:${value}`,
          });
          data.username = value;
          localStorage.setItem("username", value);
          ws.send(
            JSON.stringify({
              type: "setName",
              nickname: value,
            })
          );
        })
        .catch(() => {
          setNmae();
        });
    };
    ws.onopen = function (evt) {
      data.username = localStorage.getItem("username");
      if (data.username == null) {
        setNmae();
      } else {
        ws.send(
          JSON.stringify({
            type: "setName",
            nickname: data.username,
          })
        );
      }
    };
    // 接收数据
    ws.onmessage = (str) => {
      let json_data = JSON.parse(str.data);
      console.log(json_data);
      switch (json_data.type) {
        case "chatterList":
          data.olnum = json_data.list.length;
          break;
        case "serverInformation":
          data.system_info.push(`Player ${json_data.message}`);
          break;
        case "chat":
          data.msg_list.push({
            avatar: "",
            nickname: json_data.name,
            msg: json_data.message,
            source: json_data.name == data.username ? "A" : "B",
          });
          nextTick().then(() => {
            let ul = document.querySelector("#sort_ul");
            ul.scrollTop = ul.scrollHeight;
          });
          break;
      }
    };
    const enter = (e) => {
      e.preventDefault();
      if (data.msg_data == "") {
        return (data.input_tps = true);
      }
      data.input_tps = false;
      // TODO 发送
      ws.send(
        JSON.stringify({
          type: "chat",
          name: data.username,
          message: data.msg_data,
        })
      );
      data.msg_data = "";
    };
    const shift_enter = () => {
      // 换行
    };
    const tps = () => {
      alert("点我干嘛?");
    };
    return {
      enter,
      shift_enter,
      tps,
      ...toRefs(data),
    };
  },
};
</script>
